from prefect import __development_base_path__
from prefect.settings.models.root import Settings, _get_settings_accessors


def _format_literal(name: str, values: list[str]) -> str:
    literals = "\n".join(f'    "{value}",' for value in values)
    return f"{name}: TypeAlias = Literal[\n{literals}\n]\n"


def main():
    setting_keys = _get_settings_accessors(Settings)
    accessors = sorted(set(setting_keys.values()))

    contents = "\n".join(
        [
            "# This file is generated by `scripts/generate_settings_types.py`.",
            "# Update the generation script to update this file.",
            "from typing import Literal, TypeAlias",
            "",
            _format_literal("SettingAccessor", accessors),
        ]
    )

    (
        __development_base_path__ / "src" / "prefect" / "settings" / "_types.py"
    ).write_text(contents)


if __name__ == "__main__":
    main()
